const { default: party } = await import('https://cdn.jsdelivr.net/npm/party-js@2.2.0/+esm');
const options = data.count ? {count:party.variation.range(data.count[0], data.count[1])} : {};
const emitter = (data.effect ?? 'confetti') === 'sparkles' ? party.sparkles(target, options) : party.confetti(target, options);

